import React, { useEffect, useState, useCallback } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Plus, Trash2, X, Save, Calendar, ArrowUpRight, ShoppingCart 
} from 'lucide-react';

const Cartoes = () => {
  const [cartoes, setCartoes] = useState([]);
  const [compras, setCompras] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [selectedCartao, setSelectedCartao] = useState(null);
  const [loading, setLoading] = useState(true);
  
  const [novoCartao, setNovoCartao] = useState({
    nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#6366f1'
  });

  const mesAtual = new Date().getMonth();
  const anoAtual = new Date().getFullYear();

  const fecharModais = useCallback(() => {
    setShowModal(false);
    setSelectedCartao(null);
  }, []);

  useEffect(() => {
    const handleEsc = (event) => {
      if (event.key === 'Escape') fecharModais();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [fecharModais]);

  useEffect(() => {
    fetchDados();
  }, []);

  async function fetchDados() {
    setLoading(true);
    const { data: cData } = await supabase.from('cartoes').select('*').order('nome');
    const { data: compData } = await supabase.from('compras').select('*');
    setCartoes(cData || []);
    setCompras(compData || []);
    setLoading(false);
  }

  // NOVA LÓGICA: O limite disponível subtrai o VALOR TOTAL de todas as compras 
  // que ainda possuem parcelas a vencer ou que foram feitas no mês.
  const calcularDisponivel = (cartaoNome, limite) => {
    const totalComprometido = compras.reduce((acc, item) => {
      if (item.cartao !== cartaoNome) return acc;

      const dataCompra = new Date(item.data_compra);
      const numParcelas = item.num_parcelas || 1;
      
      // Data da ÚLTIMA parcela desta compra
      const dataUltimaParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + (numParcelas - 1), 1);
      const dataFiltroAtual = new Date(anoAtual, mesAtual, 1);

      // Se a última parcela ainda não venceu (ou vence este mês), o valor total ainda ocupa limite
      if (dataUltimaParcela >= dataFiltroAtual) {
        return acc + parseFloat(item.valor_total);
      }
      
      return acc;
    }, 0);

    return limite - totalComprometido;
  };

  async function handleSave(e) {
    e.preventDefault();
    const { error } = await supabase.from('cartoes').insert([{ 
      ...novoCartao, 
      limite: parseFloat(novoCartao.limite),
      dia_fechamento: parseInt(novoCartao.dia_fechamento) || 1,
      dia_vencimento: parseInt(novoCartao.dia_vencimento) || 1
    }]);
    if (!error) {
      fecharModais();
      setNovoCartao({ nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#6366f1' });
      fetchDados();
    }
  }

  const formatMoney = (v) => `R$ ${parseFloat(v).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;

  return (
    <div className="fade-in" style={{ paddingBottom: '40px' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: '2rem', fontWeight: '800' }}>Minha Carteira</h1>
          <p style={{ color: 'var(--text-muted)' }}>O limite disponível considera o valor total das compras parceladas.</p>
        </div>
        <button className="btn-primary" onClick={() => setShowModal(true)}>
          <Plus size={20} /> Novo Cartão
        </button>
      </header>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(340px, 1fr))', gap: '30px' }}>
        {cartoes.map(cartao => {
          const disponivel = calcularDisponivel(cartao.nome, cartao.limite);
          const perc = Math.max(0, (disponivel / cartao.limite) * 100);

          return (
            <div key={cartao.id} className="card-cartao" 
              onClick={() => setSelectedCartao(cartao)}
              style={{ 
                background: `linear-gradient(135deg, ${cartao.cor}, #0f172a)`, 
                color: 'white', padding: '32px', borderRadius: '24px', cursor: 'pointer',
                minHeight: '220px', display: 'flex', flexDirection: 'column', justifyContent: 'space-between',
                boxShadow: `0 20px 25px -5px ${cartao.cor}44`, position: 'relative', overflow: 'hidden'
              }}>
              
              <div style={{ display: 'flex', justifyContent: 'space-between', zIndex: 1 }}>
                <div>
                   <span style={{ fontSize: '0.75rem', fontWeight: '600', opacity: 0.8 }}>BANCO</span>
                   <div style={{ fontWeight: 800, fontSize: '1.4rem' }}>{cartao.nome}</div>
                </div>
                <CreditCard size={32} opacity={0.6} />
              </div>
              
              <div style={{ zIndex: 1 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '8px' }}>
                   <div>
                      <small style={{ opacity: 0.7, fontSize: '0.7rem' }}>LIMITE DISPONÍVEL</small>
                      <div style={{ fontSize: '1.6rem', fontWeight: 800 }}>{formatMoney(disponivel)}</div>
                   </div>
                   <div style={{ fontSize: '0.85rem', fontWeight: '600' }}>{Math.round(perc)}%</div>
                </div>
                <div style={{ background: 'rgba(255,255,255,0.15)', height: '8px', borderRadius: '12px', overflow: 'hidden' }}>
                  <div style={{ background: 'white', height: '100%', width: `${perc}%`, transition: 'width 1s' }} />
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* MODAL DE COMPRAS - CORRIGIDO */}
      {selectedCartao && (
        <div className="modal-overlay" onClick={fecharModais} style={{ backdropFilter: 'blur(8px)', zIndex: 1000 }}>
          <div className="modal-content fade-in" onClick={e => e.stopPropagation()} 
            style={{ maxWidth: '550px', width: '95%', borderRadius: '32px', padding: '0', overflow: 'hidden' }}>
            
            <div style={{ background: selectedCartao.cor, padding: '30px', color: 'white' }}>
               <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <h2 style={{ margin: 0 }}>{selectedCartao.nome}</h2>
                  <X style={{ cursor: 'pointer' }} onClick={fecharModais} />
               </div>
               <div style={{ marginTop: '10px', opacity: 0.9 }}>
                 Limite Total: {formatMoney(selectedCartao.limite)}
               </div>
            </div>

            <div style={{ padding: '30px', background: 'white' }}>
              <h4 style={{ margin: '0 0 20px 0' }}>Lançamentos deste Mês:</h4>
              <div style={{ maxHeight: '350px', overflowY: 'auto' }}>
                {compras
                  .filter(c => c.cartao === selectedCartao.nome)
                  .map((item, idx) => {
                    const numParcelas = item.num_parcelas || 1;
                    let infoMês = null;

                    for (let i = 0; i < numParcelas; i++) {
                      const dC = new Date(item.data_compra);
                      const dP = new Date(dC.getFullYear(), dC.getMonth() + i, 1);
                      if (dP.getMonth() === mesAtual && dP.getFullYear() === anoAtual) {
                        infoMês = { atual: i + 1, total: numParcelas, valor: parseFloat(item.valor_total) / numParcelas };
                      }
                    }

                    if (!infoMês) return null;

                    return (
                      <div key={idx} style={{ display: 'flex', justifyContent: 'space-between', padding: '15px', borderRadius: '12px', background: '#f8fafc', marginBottom: '10px', border: '1px solid #eee' }}>
                        <div>
                          <div style={{ fontWeight: '700' }}>{item.descricao}</div>
                          <div style={{ fontSize: '0.8rem', color: '#666' }}>
                            {item.parcelado ? `Parcela ${infoMês.atual}/${infoMês.total}` : 'À Vista'}
                          </div>
                        </div>
                        <div style={{ fontWeight: '800' }}>{formatMoney(infoMês.valor)}</div>
                      </div>
                    );
                  })}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* MODAL DE CADASTRO */}
      {showModal && (
        <div className="modal-overlay" onClick={fecharModais}>
          <div className="modal-content" onClick={e => e.stopPropagation()} style={{ borderRadius: '24px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
               <h3>Novo Cartão</h3>
               <X style={{ cursor: 'pointer' }} onClick={fecharModais} />
            </div>
            <form onSubmit={handleSave} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
               <input className="form-control" placeholder="Banco" required onChange={e => setNovoCartao({...novoCartao, nome: e.target.value})} />
               <input className="form-control" type="number" placeholder="Limite Total" required onChange={e => setNovoCartao({...novoCartao, limite: e.target.value})} />
               <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                 <input className="form-control" type="number" placeholder="Dia Fechamento" onChange={e => setNovoCartao({...novoCartao, dia_fechamento: e.target.value})} />
                 <input className="form-control" type="number" placeholder="Dia Vencimento" onChange={e => setNovoCartao({...novoCartao, dia_vencimento: e.target.value})} />
               </div>
               <input type="color" className="form-control" value={novoCartao.cor} onChange={e => setNovoCartao({...novoCartao, cor: e.target.value})} style={{ height: '45px' }} />
               <button type="submit" className="btn-primary">Criar Cartão</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Cartoes;
